+
+  describe("command options", () => {
+    test("passes cwd option", async () => {
+      const calls: { cwd?: string }[] = [];
+      const runner = {
+        run: async (
+          _command: string,
+          _args: string[],
+          options?: { cwd?: string },
+        ) => {
+          calls.push({ cwd: options?.cwd });
+          const data = {
+            configured: true,
+            default_workflow: "main",
+            workflow_count: 0,
