+          return { stdout: envelope(data), stderr: "", exitCode: 0 };
+        },
+      };
+      const client = createAprClient({ runner, timeout: 30000 });
+
+      await client.getStatus({ timeout: 10000 });
+
+      expect(calls[0]?.timeout).toBe(10000);
+    });
+  });
+});

